const DEFAULT_LOCAL_CONFIDENCE_THRESHOLD = 0.6;

function clamp01(value: number): number {
  if (Number.isNaN(value)) return DEFAULT_LOCAL_CONFIDENCE_THRESHOLD;
  if (value < 0) return 0;
  if (value > 1) return 1;
  return value;
}

