  const parsed = Number(process.env.PRIVACY_LOCAL_CONFIDENCE_THRESHOLD);

  return {
    localConfidenceThreshold: clamp01(parsed || DEFAULT_LOCAL_CONFIDENCE_THRESHOLD),
  };
